settings.custom_liquid:
{% if product.tags contains 'sum-books-offer' %}
  <div style="background-color:#f9f9f9; padding: 20px; border-radius: 8px; margin-bottom: 30px;">
    <h3 style="text-align: center;"><strong>عرض مميز</strong></h3>
    <p style="text-align: center; font-size: 16px; margin-bottom: 20px;">
      🎉🎉 أي كتابين تختارهم من <strong>الكتب الشاملة</strong> بـ <strong>699 جنيه</strong> فقط
    </p>

    <div style="display: flex; overflow-x: auto; gap: 15px; padding: 10px;">
      {% assign books_handles = "sales-book,entrepreneurship-book,career-success,culture-corporate,personal-dev-book,productivity-book,leadership-management,marketing-book" | split: "," %}
      {% for handle in books_handles %}
        {% assign book = all_products[handle] %}
        {% if book %}
          <div style="min-width: 200px; text-align: center; border: 1px solid #eee; padding: 10px; border-radius: 8px;">
            <a href="{{ book.url }}">
              {% if book.featured_image %}
                <img src="{{ book.featured_image | img_url: 'medium' }}" alt="{{ book.title }}" style="width: 100%; border-radius: 6px;">
              {% else %}
                <div style="width: 100%; height: 200px; background: #eee; display: flex; align-items: center; justify-content: center; border-radius: 6px;">No image</div>
              {% endif %}
              <p style="font-size: 14px; margin-top: 8px;">{{ book.title }}</p>
            </a>

            {% if book.variants.size == 1 %}
              <button class="custom-add-to-cart" data-variant-id="{{ book.variants.first.id }}" style="margin-top: 8px; background-color: #1c8d66; color: white; border: none; padding: 8px 12px; border-radius: 6px; cursor: pointer;">
                أضف إلى السلة
              </button>
            {% else %}
              <a href="{{ book.url }}" style="display: inline-block; margin-top: 8px; background-color: #ccc; color: #000; padding: 8px 12px; border-radius: 6px;">اختر نوع المنتج</a>
            {% endif %}
          </div>
        {% endif %}
      {% endfor %}
    </div>
  </div>

  <!-- Toast notification -->
  <style>
    .custom-toast {
      position: fixed;
      bottom: 20px;
      left: 50%;
      transform: translateX(-50%);
      background: #1c8d66;
      color: #fff;
      padding: 12px 20px;
      border-radius: 6px;
      font-size: 14px;
      z-index: 9999;
      opacity: 0;
      transition: opacity 0.4s ease;
    }

    .custom-toast.show {
      opacity: 1;
    }
  </style>

  <div id="custom-toast" class="custom-toast">✅ تمت إضافة المنتج للسلة</div>

  <!-- JS to handle add-to-cart + toast -->
  <script>
    function showCustomToast(message) {
      const toast = document.getElementById('custom-toast');
      toast.textContent = message;
      toast.classList.add('show');
      setTimeout(() => {
        toast.classList.remove('show');
      }, 3000);
    }

    document.querySelectorAll('.custom-add-to-cart').forEach(button => {
      button.addEventListener('click', function () {
        const variantId = this.dataset.variantId;

        fetch('/cart/add.js', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({ id: variantId, quantity: 1 })
        })
        .then(response => {
          if (!response.ok) throw new Error('خطأ في الإضافة للسلة');
          return response.json();
        })
        .then(data => {
          showCustomToast('✅ تمت إضافة المنتج للسلة');
          const cartDrawer = document.querySelector('cart-drawer');
          if (cartDrawer && typeof cartDrawer.open === 'function') {
            cartDrawer.open();
          }
        })
        .catch(err => {
          console.error('Error:', err);
          showCustomToast('❌ حدث خطأ أثناء الإضافة');
        });
      });
    });
  </script>
{% endif %}
